This is a missed-optimization in IR.

The following program reveals the missed optimization.
The source program is
```llvm
define void @pr108052(i64 %n) {
entry:
  br label %for.body

for.exit:                                         ; preds = %for.body
  ret void

for.body:                                         ; preds = %for.body, %entry
  %indvar = phi i64 [ 0, %entry ], [ %inc, %for.body ]
  call void @llvm.experimental.noalias.scope.decl(metadata !0)
  %inc = add nuw i64 %indvar, 1
  %exitcond.not = icmp eq i64 %inc, %n
  br i1 %exitcond.not, label %for.exit, label %for.body
}

; Function Attrs: nocallback nofree nosync nounwind willreturn memory(inaccessiblemem: readwrite)
declare void @llvm.experimental.noalias.scope.decl(metadata) #0

attributes #0 = { nocallback nofree nosync nounwind willreturn memory(inaccessiblemem: readwrite) }

!0 = !{!1}
!1 = distinct !{!1, !2, !"x: %a"}
!2 = distinct !{!2, !"x"}

```

However, current LLVM cannot optimize the source program. The expected optimized program is
```llvm
define void @pr108052(i64 %n) {
entry:
  br label %for.exit

for.exit:                                         ; preds = %entry
  ret void
}

; Function Attrs: nocallback nosync nounwind willreturn memory(inaccessiblemem: readwrite)
declare void @llvm.experimental.noalias.scope.decl(metadata) #0

attributes #0 = { nocallback nosync nounwind willreturn memory(inaccessiblemem: readwrite) }

```
Please modify the following code in llvm/lib/IR/User.cpp:User::isDroppable to implement the missed optimization:
```cpp

